// Example of routing a player prompt to the local model via Event Bus
class PromptRouter {
  constructor(private eventBus: EventBus) {}

  async routePrompt(playerInput: string): Promise<string> {
    // Dispatch event to MediaPipe-loaded model
    const response = await this.eventBus.dispatch(
      'prompt-to-model',
      playerInput
    );
    return response;
  }
}
